import React from "react";

function About() {
  return (
    <section className="about-page container">
      <div className="about-card">
        <h2>About UrbanDrainX</h2>
        <p>
          UrbanDrainX is built to modernize city drainage infrastructure with
          continuous monitoring and predictive analytics.
        </p>

        <ul>
          <li>Real-time water level and flow-rate tracking from IoT sensors</li>
          <li>Automated risk scoring for proactive maintenance planning</li>
          <li>Priority-based alerting for critical overflow conditions</li>
          <li>Historical data insights for resilient smart-city operations</li>
        </ul>
      </div>
    </section>
  );
}

export default About;
